  [pscustomobject]@{ Label = 'newsapi --topic business'; Args = @('newsapi','--topic','business') }
)
$failed = @()
foreach ($t in $tests) {
  Write-Host "`n>>> node run.mjs $($t.Label)"
  & node run.mjs @($t.Args)
  $code = $LASTEXITCODE
  Write-Host "<<< exit $code"
  if ($code -ne 0) {
    $failed += $t.Label
  }
}
Write-Host "`nMorning sequence failures: $($failed.Count)"
foreach ($f in $failed) {
  Write-Host "FAIL $f"
}
if ($failed.Count -gt 0) {
  exit 1
}

