// 8-K items worth calling out in signals
const SIGNAL_ITEMS = {
  '1.01': 'Material contract',
  '1.02': 'Contract termination ⚠️',
  '2.02': 'Earnings results',
  '2.06': 'Material impairment 🔴',
  '4.01': 'Auditor change ⚠️',
