    a['Awarding Agency'] || 'N/A',
    (a['Description'] || 'N/A').slice(0, 60),
  ]);

  const note = buildNote({
    frontmatter: {
      title: 'Recent Federal Contract Awards — USASpending',
      source: 'USASpending API',
