      symbol: sym,
      company: p.companyName,
      date_pulled: today(),
      domain: 'market',
      data_type: 'snapshot',
      frequency: 'on-demand',
      signal_status: 'clear',
      signals: [],
      tags: ['equities', 'profile', sym.toLowerCase(), 'fmp'],
