  console.log(`📊 FMP: Fetching income statement for ${sym}...`);

  const data = await getJson(`${stableBaseUrl}/income-statement?symbol=${sym}&period=annual&limit=5&apikey=${apiKey}`);
  if (!Array.isArray(data) || data.length === 0) {
