      }
    }

    if (signals.length > 0) {
      console.log(`\n⚡ ${signals.length} opportunity signal(s):`);
      signals.forEach(s => console.log(`  🟡 ${s.message}`));
    }

    const rows = opportunitiesData.map(opp => Object.freeze([
