Run $tests = @(
  [pscustomobject]@{ Label = 'validate'; Args = @('validate') }
  [pscustomobject]@{ Label = 'sam --all'; Args = @('sam','--all') }
  [pscustomobject]@{ Label = 'fmp --profile AAPL'; Args = @('fmp','--profile','AAPL') }
  [pscustomobject]@{ Label = 'fmp --options SPY'; Args = @('fmp','--options','SPY') }
  [pscustomobject]@{ Label = 'playbook housing-cycle'; Args = @('playbook','housing-cycle') }
  [pscustomobject]@{ Label = 'bea --gdp'; Args = @('bea','--gdp') }
  [pscustomobject]@{ Label = 'treasury --yields'; Args = @('treasury','--yields') }
  [pscustomobject]@{ Label = 'usaspending --recent'; Args = @('usaspending','--recent') }
)
$failed = @()
foreach ($t in $tests) {
  Write-Host "`n>>> node run.mjs $($t.Label)"
  & node run.mjs @($t.Args)
  $code = $LASTEXITCODE
  Write-Host "<<< exit $code"
  if ($code -ne 0) {
    $failed += $t.Label
  }
}
Write-Host "`nTargeted failures: $($failed.Count)"
foreach ($f in $failed) {
  Write-Host "FAIL $f"
}
if ($failed.Count -gt 0) {
  exit 1
}

