 * @returns {Promise<{ filePath: string, signals: Array }>}
 */
async function pullOpportunities(keyword, apiKey) {
  console.log('📋 SAM.gov: Pulling opportunities for "' + keyword + '"');

  try {
    const postedFrom = (() => {
      const d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      const mm = String(d.getMonth() + 1).padStart(2, '0');
      const dd = String(d.getDate()).padStart(2, '0');
      const yyyy = d.getFullYear();
      return `${mm}/${dd}/${yyyy}`;
    })();
    const postedTo = (() => {
      const d = new Date();
      const mm = String(d.getMonth() + 1).padStart(2, '0');
      const dd = String(d.getDate()).padStart(2, '0');
      const yyyy = d.getFullYear();
      return `${mm}/${dd}/${yyyy}`;
    })();

    const url = `https://api.sam.gov/opportunities/v2/search?limit=25&offset=0&api_key=${apiKey}&postedFrom=${postedFrom}&postedTo=${postedTo}&title=${encodeURIComponent(keyword)}`;
