content.title:
Run $thesisData = @{
'AI Power Infrastructure' = @{allocation_priority='high'; allocation_rank=1; why_now='Hyperscaler capex and power scarcity are creating visible pricing power for dispatchable generation, transformers, and data-center electrical gear.'; variant_perception='The market still treats this as a temporary AI capex burst instead of a multi-year grid and power bottleneck.'; next_catalyst='Hyperscaler power-contract announcements and grid-equipment backlog updates through 2026.'; disconfirming_evidence='Power-per-FLOP falls fast enough that hyperscaler load growth stops outrunning grid capacity.'; expected_upside='Multi-year rerating plus earnings revision cycle in utilities and grid-infrastructure names.'; expected_downside='Capex pause or faster supply normalization compresses the scarcity premium.'; position_sizing='Core 3-6% theme basket, concentrated in GEV, VST, NRG, ETN, and STRL.'; required_sources=@('[[EIA_Electricity]]','[[SEC EDGAR API]]','[[USASpending API]]'); required_pull_families=@('eia --all','sec --aipower','usaspending --recent')};
'Housing Supply Correction' = @{allocation_priority='high'; allocation_rank=1; why_now='Rate cuts, lock-in relief, and chronic underbuilding can re-open demand while keeping supply structurally tight.'; variant_perception='Consensus still frames housing as a pure rate trade instead of a prolonged supply-shortage cycle.'; next_catalyst='Mortgage-rate moves, builder confidence, and housing starts through the next Fed easing steps.'; disconfirming_evidence='Unemployment-led demand destruction overwhelms the structural supply shortage.'; expected_upside='Earnings and multiple expansion for builders as qualified-buyer volume reaccelerates.'; expected_downside='A recession or persistent 7%+ mortgage rates would hit volumes and margins together.'; position_sizing='Core 3-5% housing basket led by DHI and NVR, with smaller exposures in LEN, TOL, TMHC, and SKY.'; required_sources=@('[[FRED Housing Series]]','[[Census Bureau Housing Data]]','[[FHFA House Price Index]]','[[OpenFEMA API]]'); required_pull_families=@('fred --group housing','fred --group rates','openfema --recent','playbook housing-cycle')};
'Defense AI Autonomous Warfare' = @{allocation_priority='high'; allocation_rank=1; why_now='Real-world conflict is accelerating software-defined warfare and the US procurement system is now funding AI/autonomy programs at scale.'; variant_perception='Investors still underweight the durability of software and cloud capture inside defense budgets.'; next_catalyst='Maven, JWCC, DARPA, SOCOM, and NDAA budget updates over the next 12 months.'; disconfirming_evidence='Congress or the DoD freezes autonomous-systems adoption after political or operational backlash.'; expected_upside='Sustained contract flow and multiple expansion for software-first defense winners.'; expected_downside='Binary contract losses or a peace-dividend narrative hits multiples before revenue catches up.'; position_sizing='Core 3-6% defense-AI basket with PLTR and integrators as anchors.'; required_sources=@('[[USASpending API]]','[[SAM_Gov]]','[[SEC EDGAR API]]','[[NewsAPI]]'); required_pull_families=@('usaspending --recent','sam --opportunities','sec --defenseai','newsapi --topic business')};
'Dollar Debasement Hard Money' = @{allocation_priority='high'; allocation_rank=1; why_now='Fiscal dominance, debt issuance, and monetary accommodation continue to support hard-asset outperformance.'; variant_perception='Many investors still assume inflation has normalized enough to preserve fiat purchasing power.'; next_catalyst='Treasury issuance, real-rate direction, and fiscal-deficit updates over 2026.'; disconfirming_evidence='Real yields rise materially and fiscal discipline returns faster than expected.'; expected_upside='Gold, hard-money equities, and scarce real assets reprice higher on sustained fiat skepticism.'; expected_downside='Disinflation plus high real yields compress the hard-money narrative.'; position_sizing='Core 3-5% hard-money sleeve, with gold-linked and scarce-asset exposure.'; required_sources=@('[[FRED API]]','[[Treasury Direct API]]','[[US Treasury Data]]','[[BEA API]]'); required_pull_families=@('fred --group rates','treasury --yields','bea --gdp','newsapi --topic business')};
'Semiconductor Sovereignty CHIPS Act' = @{allocation_priority='high'; allocation_rank=1; why_now='Industrial policy, export controls, and AI compute demand are keeping domestic semiconductor capacity strategically scarce.'; variant_perception='The market underestimates how persistent policy support and geopolitical fragmentation will be.'; next_catalyst='CHIPS disbursements, export-control changes, and AI server demand updates.'; disconfirming_evidence='Capacity ramps ahead of demand and policy urgency fades without further restrictions.'; expected_upside='Foundry, equipment, and sovereign-supply-chain beneficiaries earn premium multiples.'; expected_downside='Cyclical oversupply or subsidy disappointments cut the sovereign-premium narrative.'; position_sizing='Core 2-4% semiconductor sovereignty sleeve focused on strategic bottlenecks.'; required_sources=@('[[USASpending API]]','[[SEC EDGAR API]]','[[NewsAPI]]','[[Alpha Vantage]]'); required_pull_families=@('usaspending --recent','sec --semi','newsapi --topic business','alphavantage --quote SOXX')};
'Nuclear Renaissance SMRs' = @{allocation_priority='high'; allocation_rank=1; why_now='Power scarcity, grid reliability needs, and energy-security policy are reviving nuclear as dispatchable clean baseload.'; variant_perception='Markets still treat nuclear as politically stalled rather than as the cleanest answer to rising power demand.'; next_catalyst='SMR licensing, utility procurement, and data-center power deals.'; disconfirming_evidence='Permitting delays or cost overruns keep nuclear out of real project pipelines.'; expected_upside='Utilities, fuel, and nuclear-enablement names rerate as projects move from concept to funded build.'; expected_downside='The thesis remains too early and capital gets trapped in long-duration promises.'; position_sizing='Core 2-4% thematic sleeve, scaled only on real permitting or procurement progress.'; required_sources=@('[[EIA_Electricity]]','[[USASpending API]]','[[SEC EDGAR API]]'); required_pull_families=@('eia --all','usaspending --recent','sec --nuclear','newsapi --topic business')};
