$files = Get-ChildItem '10_Theses' -File -Filter *.md;
foreach ($file in $files) {
  $base = $file.BaseName;
  if (-not $thesisData.ContainsKey($base)) { continue }
  $data = $thesisData[$base];
  $content = Get-Content $file.FullName -Raw;
  $fmMatch = [regex]::Match($content, '(?s)^---\r?\n(.*?)\r?\n---\r?\n');
  if (-not $fmMatch.Success) { continue }
  $frontmatter = $fmMatch.Groups[1].Value;
  $body = $content.Substring($fmMatch.Length);
  $insert = @(
    ('allocation_priority: "' + $data.allocation_priority + '"'),
    ('allocation_rank: ' + $data.allocation_rank),
    ('why_now: "' + $data.why_now.Replace('"','''') + '"'),
    ('variant_perception: "' + $data.variant_perception.Replace('"','''') + '"'),
    ('next_catalyst: "' + $data.next_catalyst.Replace('"','''') + '"'),
    ('disconfirming_evidence: "' + $data.disconfirming_evidence.Replace('"','''') + '"'),
    ('expected_upside: "' + $data.expected_upside.Replace('"','''') + '"'),
    ('expected_downside: "' + $data.expected_downside.Replace('"','''') + '"'),
    ('position_sizing: "' + $data.position_sizing.Replace('"','''') + '"'),
    ('required_sources: [' + (($data.required_sources | ForEach-Object { '"' + $_ + '"' }) -join ', ') + ']'),
    ('required_pull_families: [' + (($data.required_pull_families | ForEach-Object { '"' + $_ + '"' }) -join ', ') + ']')
  ) -join "`r`n";
  if ($frontmatter -notmatch '(?m)^allocation_priority:') {
    $frontmatter = [regex]::Replace($frontmatter, '(?m)^timeframe:\s*"[^"]+"\s*$', "$0`r`n$insert", 1)
  }
  $scorecard = @(
    '## Investment Scorecard',
    '',
    ('- **Allocation Priority**: ' + $data.allocation_priority + ' (' + $data.allocation_rank + ')'),
    ('- **Why now**: ' + $data.why_now),
    ('- **Variant perception**: ' + $data.variant_perception),
    ('- **Next catalyst**: ' + $data.next_catalyst),
    ('- **Disconfirming evidence**: ' + $data.disconfirming_evidence),
    ('- **Expected upside**: ' + $data.expected_upside),
    ('- **Expected downside**: ' + $data.expected_downside),
    ('- **Sizing rule**: ' + $data.position_sizing),
    '',
    '## Required Evidence',
    '',
    ('- **Source notes**: ' + ($data.required_sources -join ', ')),
    ('- **Pull families**: ' + ($data.required_pull_families -join ', ')),
    ''
  ) -join "`r`n";
  if ($body -notmatch '(?m)^## Investment Scorecard') {
    $body = [regex]::Replace($body, '(?m)^## Position Sizing & Risk', "$scorecard`r`n## Position Sizing & Risk", 1)
  }
  $newContent = "---`r`n$frontmatter`r`n---`r`n$body";
  Set-Content $file.FullName $newContent;
}
