  $priorityMatch = [regex]::Match($frontmatter, '(?m)^allocation_priority:\s*"?(.*?)"?\s*$')
  if ($priorityMatch.Success) {
    $priority = $priorityMatch.Groups[1].Value
  }

  if ($frontmatter -notmatch '(?m)^monitor_status:') {
