    $body = [regex]::Replace($body, '(?m)^## Position Sizing & Risk', "$monitorBlock`r`n## Position Sizing & Risk", 1)
  }

  $updated = "---`r`n$frontmatter`r`n---`r`n$body"
  Set-Content $file.FullName $updated
}

